WITH AUX AS (SELECT (CASE TIPOESTADO WHEN 'RP' THEN 'P' WHEN 'P' THEN 'P' WHEN 'E' THEN 'E' ELSE '0' END) ESTADO,  
                NVL(PROYECTOS.PRODUCTO,' ') PRODUCTO_PROYECTO, 
                NVL(PROYECTOS.UNIDAD,' ') UNIDAD_PROYECTO, 
                NVL(PROYECTOS.CANTIDAD, 0) CANTIDAD_PROYECTO, 
                SUM(PORCENTAJE1)PORCENTAJE1,
                SUM(PORCENTAJE2)PORCENTAJE2,SUM(PORCENTAJE3)PORCENTAJE3,
                SUM(PORCENTAJE4)PORCENTAJE4,SUM(PORCENTAJE5)PORCENTAJE5,
                SUM(PORCENTAJE6)PORCENTAJE6,SUM(PORCENTAJE7)PORCENTAJE7,
                SUM(PORCENTAJE8)PORCENTAJE8,SUM(PORCENTAJE9)PORCENTAJE9,
                SUM(PORCENTAJE10)PORCENTAJE10,SUM(PORCENTAJE11)PORCENTAJE11,
                SUM(PORCENTAJE12)PORCENTAJE12,SUM(VALOR1) VALOR1,
                SUM(VALOR2)VALOR2,SUM(VALOR3)VALOR3,
                SUM(VALOR4)VALOR4,SUM(VALOR5)VALOR5,SUM(VALOR6)VALOR6,
                SUM(VALOR7)VALOR7,SUM(VALOR8)VALOR8,
                SUM(VALOR9)VALOR9,SUM(VALOR10)VALOR10,
                SUM(VALOR11)VALOR11,SUM(VALOR12)VALOR12,
                PROYECTOS.PERIOCIDAD, 
                PROGRAMACION.CODIGOPROYECTO, 
                PROGRAMACION.COMPANIA
            FROM PROGRAMACION 
                LEFT JOIN COMPONENTES ON 
                    PROGRAMACION.COMPANIA               = COMPONENTES.COMPANIA
                    AND PROGRAMACION.CODIGOPROYECTO       = COMPONENTES.CODIGOPROYECTO
                    AND PROGRAMACION.CODIGOCOMPONENTE     = COMPONENTES.CODIGO
                LEFT JOIN PROYECTOS ON 
                    COMPONENTES.COMPANIA              = PROYECTOS.COMPANIA
                    AND COMPONENTES.CODIGOPROYECTO          = PROYECTOS.CODIGO
            WHERE PROGRAMACION.COMPANIA = s$compania$s
                AND PROGRAMACION.CODIGOPROYECTO ='s$proyecto$s'
                AND TO_CHAR(COMPONENTES.VIGENCIA) = CASE WHEN 's$vigencia$s'= 'TODAS' THEN TO_CHAR(COMPONENTES.VIGENCIA) ELSE 's$vigencia$s' END
            GROUP BY PROGRAMACION.TIPOESTADO, 
                PROYECTOS.PRODUCTO, 
                PROYECTOS.UNIDAD, 
                PROYECTOS.CANTIDAD, 
                PROYECTOS.PERIOCIDAD, 
                PROGRAMACION.CODIGOPROYECTO, 
                PROGRAMACION.COMPANIA
            ORDER BY PROGRAMACION.TIPOESTADO DESC)
SELECT 
    ESTADO,
    PRODUCTO_PROYECTO,
    UNIDAD_PROYECTO,
    CANTIDAD_PROYECTO,
    VALOR1 SVALOR1, 
    PORCENTAJE1 SPORCENTAJE1, 
    VALOR1+VALOR2 SVALOR2, 
    PORCENTAJE1+PORCENTAJE2 SPORCENTAJE2,  
    VALOR1+VALOR2+VALOR3 SVALOR3, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3 SPORCENTAJE3,
    VALOR1+VALOR2+VALOR3+VALOR4 SVALOR4, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4 SPORCENTAJE4, 
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5 SVALOR5, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5 SPORCENTAJE5, 
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5+VALOR6 SVALOR6, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5+PORCENTAJE6 SPORCENTAJE6,  
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5+VALOR6+VALOR7 SVALOR7, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5+PORCENTAJE6+PORCENTAJE7 SPORCENTAJE7, 
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5+VALOR6+VALOR7+VALOR8 SVALOR8, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5+PORCENTAJE6+PORCENTAJE7+PORCENTAJE8 SPORCENTAJE8, 
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5+VALOR6+VALOR7+VALOR8+VALOR9 SVALOR9, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5+PORCENTAJE6+PORCENTAJE7+PORCENTAJE8+PORCENTAJE9 SPORCENTAJE9, 
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5+VALOR6+VALOR7+VALOR8+VALOR9+VALOR10 SVALOR10, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5+PORCENTAJE6+PORCENTAJE7+PORCENTAJE8+PORCENTAJE9+PORCENTAJE10 SPORCENTAJE10, 
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5+VALOR6+VALOR7+VALOR8+VALOR9+VALOR10+VALOR11 SVALOR11, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5+PORCENTAJE6+PORCENTAJE7+PORCENTAJE8+PORCENTAJE9+PORCENTAJE10+PORCENTAJE11 SPORCENTAJE11, 
    VALOR1+VALOR2+VALOR3+VALOR4+VALOR5+VALOR6+VALOR7+VALOR8+VALOR9+VALOR10+VALOR11+VALOR12 SVALOR12, 
    PORCENTAJE1+PORCENTAJE2+PORCENTAJE3+PORCENTAJE4+PORCENTAJE5+PORCENTAJE6+PORCENTAJE7+PORCENTAJE8+PORCENTAJE9+PORCENTAJE10+PORCENTAJE11+PORCENTAJE12 SPORCENTAJE12,  
     TOTALVALOR, 
     TOTALPORCENTAJE,
    PERIOCIDAD, 
    CODIGOPROYECTO, 
    COMPANIA
    FROM AUX
